const input = $input.first().json || {};
let rows = input.result || [];
if (typeof rows === 'string') { try { rows = JSON.parse(rows); } catch(e) { rows = []; } }
if (!Array.isArray(rows)) rows = [];

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const newProblems = rows.filter(r => r.status === 'new_problem');
const newlyCrossed = rows.filter(r => r.status === 'newly_crossed_50');
const chronic = rows.filter(r => r.status === 'chronic');

if (rows.length === 0) {
  return [{json: {skip: true, text: null, count: 0}}];
}

function lineOf(r, showPrior) {
  const priorStr = showPrior && r.total_prior > 0 ? ' (\u0431\u044b\u043b\u043e ' + r.cancel_rate_prior + '%)' : '';
  return '\u2022 <b>' + esc(r.sku) + '</b> \u2014 ' + r.cancel_rate_7d + '% (' + r.cancelled_7d + '/' + r.total_7d + ')' + priorStr + '\n  <i>' + esc((r.name||'').slice(0,75)) + '</i>\n  ' + esc((r.brand||'-').slice(0,20));
}

const parts = [];

if (newlyCrossed.length > 0) {
  parts.push('\ud83d\udd34 <b>\u041d\u043e\u0432\u044b\u0435 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u044b</b> (\u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u043f\u0435\u0440\u0435\u0441\u0435\u043a\u043b\u0438 50%):\n\n' + newlyCrossed.slice(0,10).map(r => lineOf(r, true)).join('\n\n'));
}

if (newProblems.length > 0) {
  parts.push('\u26a0\ufe0f <b>\u041d\u043e\u0432\u044b\u0435 SKU \u0441\u0440\u0430\u0437\u0443 \u0441 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u043e\u0439</b> (\u043d\u0435\u0442 \u0438\u0441\u0442\u043e\u0440\u0438\u0438 30+ \u0434\u043d\u0435\u0439):\n\n' + newProblems.slice(0,10).map(r => lineOf(r, false)).join('\n\n'));
}

if (chronic.length > 0) {
  parts.push('\ud83d\udd38 <b>\u0425\u0440\u043e\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0435</b> (\u0431\u044b\u043b\u0438 \u043f\u043b\u043e\u0445\u0438\u043c\u0438 \u0438 \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f): ' + chronic.length + ' SKU \u2014 \u0441\u043c. \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0439 \u0430\u043b\u0435\u0440\u0442 WF-R-ALERT-01.');
}

// SQL \u0434\u043b\u044f \u043c\u0430\u0441\u0441\u043e\u0432\u043e\u0439 \u0434\u0435\u0430\u043a\u0442\u0438\u0432\u0430\u0446\u0438\u0438 \u043d\u043e\u0432\u044b\u0445 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u043d\u044b\u0445
const toDeactivate = [...newProblems, ...newlyCrossed].filter(r => r.cancel_rate_7d >= 80);
if (toDeactivate.length > 0) {
  const tickers = toDeactivate.map(r => "'" + String(r.sku).replace(/'/g,"''") + "'").join(', ');
  parts.push('\n\n<b>\ud83d\udd27 SQL \u0434\u043b\u044f \u043c\u0430\u0441\u0441\u043e\u0432\u043e\u0439 \u0434\u0435\u0430\u043a\u0442\u0438\u0432\u0430\u0446\u0438\u0438 (cancel\u226580%):</b>\n<code>UPDATE products SET is_active = false WHERE ticker IN (' + tickers + ') OR slug IN (' + tickers + ');</code>');
}

const today = new Date().toISOString().slice(0,10);
const header = '\ud83d\udee1\ufe0f <b>Safety Check \u2014 New Problem SKUs</b>\n<i>' + today + ' | \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435 7\u0434 \u0441 \u043f\u0440\u0435\u0434\u044b\u0434\u0443\u0449\u0438\u043c\u0438 30\u0434</i>\n\n<b>' + rows.length + '</b> \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u043d\u044b\u0445 \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 SKU | \u043d\u043e\u0432\u044b\u0445: ' + (newProblems.length + newlyCrossed.length);

const text = header + '\n\n' + parts.join('\n\n');

return [{json: {text, count: rows.length, new_count: newProblems.length + newlyCrossed.length, rows}}];
